import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

class CSVFormatTest {

    @Test
    void testWithIgnoreSurroundingSpaces() throws Exception {
        CSVFormat original = CSVFormat.DEFAULT;
        // Call the focal method
        CSVFormat result = original.withIgnoreSurroundingSpaces();

        // The returned instance should not be the same as original if the flag changes
        assertNotNull(result);
        // It should have ignoreSurroundingSpaces == true
        assertTrue(result.getIgnoreSurroundingSpaces());

        // Calling again on an instance that already has ignoreSurroundingSpaces true returns itself
        CSVFormat secondCall = result.withIgnoreSurroundingSpaces();
        assertSame(secondCall, result);
    }
}
